&lt;h2 id=&#34;代码块展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码块展示&#34;&gt;#&lt;/a&gt; 💻 代码块展示&lt;/h2&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;figcaption&gt;&lt;span&gt;高亮示例&lt;/span&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kZXZlbG9wZXIubW96aWxsYS5vcmcvemgtQ04vZG9jcy9XZWIvSmF2YVNjcmlwdA==&#34;&gt;参考文档 mark:2,5-7&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// JavaScript 函数示例&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;greetUser&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;name&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!name) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, Guest!&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; greeting = &lt;span class=&#34;string&#34;&gt;`Hello, &lt;span class=&#34;subst&#34;&gt;$&amp;#123;name&amp;#125;&lt;/span&gt;!`&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(greeting);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; greeting;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_&#34;&gt;greetUser&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;张三&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption&gt;&lt;span&gt;命令行示例 command:(&#34;[root@localhost] $&#34;:1,3||&#34;[user@server] #&#34;:5-6)&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;pwd&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/home/user/projects&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;ls&lt;/span&gt; -la&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;total 16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;drwxr-xr-x 3 user user 4096 Jan  3 14:00 .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;drwxr-xr-x 5 user user 4096 Jan  3 13:30 ..&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;h2 id=&#34;练习题展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#练习题展示&#34;&gt;#&lt;/a&gt; 🎯 练习题展示&lt;/h2&gt;
&lt;ol&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;Hexo 是一个基于 Node.js 的静态博客框架。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;下列哪些是 Shoka 主题的特色功能？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;友链展示&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;代码高亮&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数学公式支持&lt;/li&gt;
&lt;li&gt;视频播放&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li&gt;✅ 支持友链卡片展示&lt;/li&gt;
&lt;li&gt;✅ 支持多种代码高亮&lt;/li&gt;
&lt;li&gt;✅ 支持 KaTeX 数学公式&lt;/li&gt;
&lt;li&gt;❌ 不是主要特色功能&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;Shoka 主题基于 &lt;span class=&#34;gap&#34;&gt;Hexo&lt;/span&gt; 框架开发。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;文字特效展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#文字特效展示&#34;&gt;#&lt;/a&gt; 🎨 文字特效展示&lt;/h2&gt;
&lt;p&gt;++ 下划线效果 ++&lt;br&gt;
++ 波浪线效果 ++{.wavy}&lt;br&gt;
++ 着重点效果 ++{.dot}&lt;br&gt;
++ 彩色下划线 ++{.primary}&lt;br&gt;
~~ 删除线效果～～&lt;br&gt;
== 荧光高亮效果 ==&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;rainbow&#34;&gt;赤橙黄绿青蓝紫&lt;/span&gt;&lt;br&gt;
&lt;span class=&#34;red&#34;&gt;红色文字&lt;/span&gt; &lt;span class=&#34;blue&#34;&gt;蓝色文字&lt;/span&gt; &lt;span class=&#34;green&#34;&gt;绿色文字&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;快捷键示例：&lt;span class=&#34;kbd&#34;&gt;Ctrl&lt;/span&gt; + &lt;span class=&#34;kbd primary&#34;&gt;C&lt;/span&gt;&lt;/p&gt;
&lt;h2 id=&#34;隐藏文字展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#隐藏文字展示&#34;&gt;#&lt;/a&gt; 🔒 隐藏文字展示&lt;/h2&gt;
&lt;p class=&#34;blur&#34;&gt;!! 这是隐藏的内容，鼠标悬停显示！！&lt;br&gt;
!! 这是模糊的内容，选中文字显示！！&lt;/p&gt;
&lt;h2 id=&#34;️-标签展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#️-标签展示&#34;&gt;#&lt;/a&gt; 🏷️ 标签展示&lt;/h2&gt;
&lt;p&gt;&lt;span class=&#34;label&#34;&gt;默认&lt;/span&gt; &lt;span class=&#34;label primary&#34;&gt;主要&lt;/span&gt; &lt;span class=&#34;label info&#34;&gt;信息&lt;/span&gt;&lt;br&gt;
&lt;span class=&#34;label success&#34;&gt;成功&lt;/span&gt; &lt;span class=&#34;label warning&#34;&gt;警告&lt;/span&gt; &lt;span class=&#34;label danger&#34;&gt;危险&lt;/span&gt;&lt;/p&gt;
&lt;h2 id=&#34;提醒块展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#提醒块展示&#34;&gt;#&lt;/a&gt; 📝 提醒块展示&lt;/h2&gt;
&lt;div class=&#34;note info 信息提示&#34;&gt;
&lt;p&gt;这是一个信息提示块，用于显示重要信息。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note success 成功提示&#34;&gt;
&lt;p&gt;这是一个成功提示块，表示操作成功完成。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note warning 警告提示&#34;&gt;
&lt;p&gt;这是一个警告提示块，提醒用户注意。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note danger 危险提示&#34;&gt;
&lt;p&gt;这是一个危险提示块，警告用户潜在风险。&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;标签卡展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#标签卡展示&#34;&gt;#&lt;/a&gt; 📑 标签卡展示&lt;/h2&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;demo1&#34; data-title=&#34;前端技术&#34;&gt;
&lt;h3 id=&#34;html&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#html&#34;&gt;#&lt;/a&gt; HTML&lt;/h3&gt;
&lt;p&gt;超文本标记语言，用于创建网页结构。&lt;/p&gt;
&lt;h3 id=&#34;css&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#css&#34;&gt;#&lt;/a&gt; CSS&lt;/h3&gt;
&lt;p&gt;层叠样式表，用于网页样式设计。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;demo1&#34; data-title=&#34;后端技术&#34;&gt;
&lt;h3 id=&#34;nodejs&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#nodejs&#34;&gt;#&lt;/a&gt; Node.js&lt;/h3&gt;
&lt;p&gt;基于 Chrome V8 引擎的 JavaScript 运行环境。&lt;/p&gt;
&lt;h3 id=&#34;python&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#python&#34;&gt;#&lt;/a&gt; Python&lt;/h3&gt;
&lt;p&gt;简洁优雅的编程语言，适合快速开发。&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;折叠块展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#折叠块展示&#34;&gt;#&lt;/a&gt; 📁 折叠块展示&lt;/h2&gt;
&lt;details&gt;&lt;summary&gt;primary JavaScript 基础知识&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;JavaScript 是一种高级的、解释型的编程语言。&lt;/p&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; message = &lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, World!&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(message);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;details&gt;&lt;summary&gt;success CSS 样式技巧&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;CSS 可以让网页变得更加美观。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;使用 Flexbox 布局&lt;/li&gt;
&lt;li&gt;响应式设计&lt;/li&gt;
&lt;li&gt;动画效果&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;h2 id=&#34;待办事项展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#待办事项展示&#34;&gt;#&lt;/a&gt; ✅ 待办事项展示&lt;/h2&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_0&#34; checked=&#34;true&#34; disabled=&#34;true&#34;&gt;&lt;label for=&#34;cbx_0&#34;&gt; 学习 Hexo 基础&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_1&#34; checked=&#34;true&#34; disabled=&#34;true&#34;&gt;&lt;label for=&#34;cbx_1&#34;&gt; 安装 Shoka 主题 {.success}&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_2&#34; disabled=&#34;true&#34;&gt;&lt;label for=&#34;cbx_2&#34;&gt; 配置主题功能&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_3&#34; disabled=&#34;true&#34;&gt;&lt;label for=&#34;cbx_3&#34;&gt; 编写第一篇文章 {.primary}&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;注音展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#注音展示&#34;&gt;#&lt;/a&gt; 🔤 注音展示&lt;/h2&gt;
&lt;p&gt;&lt;ruby&gt;可&lt;rp&gt;【&lt;/rp&gt;&lt;rt&gt;か&lt;/rt&gt;&lt;rp&gt;】&lt;/rp&gt;愛&lt;rp&gt;【&lt;/rp&gt;&lt;rt&gt;わい&lt;/rt&gt;&lt;rp&gt;】&lt;/rp&gt;い&lt;rt&gt;&lt;/rt&gt;犬&lt;rp&gt;【&lt;/rp&gt;&lt;rt&gt;いぬ&lt;/rt&gt;&lt;rp&gt;】&lt;/rp&gt;&lt;/ruby&gt;&lt;br&gt;
&lt;ruby&gt;Hello&lt;rp&gt;【&lt;/rp&gt;&lt;rt&gt;你好&lt;/rt&gt;&lt;rp&gt;】&lt;/rp&gt;&lt;/ruby&gt;&lt;br&gt;
&lt;ruby&gt;Hexo&lt;rp&gt;【&lt;/rp&gt;&lt;rt&gt;静态博客框架&lt;/rt&gt;&lt;rp&gt;】&lt;/rp&gt;&lt;/ruby&gt;&lt;/p&gt;
&lt;h2 id=&#34;数学公式展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数学公式展示&#34;&gt;#&lt;/a&gt; 🧮 数学公式展示&lt;/h2&gt;
&lt;p&gt;行内公式：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;E = mc^2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8141079999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;块级公式：&lt;/p&gt;
\begin{align}
\nabla \times \vec{\mathbf{B}} -\, \frac1c\, \frac{\partial\vec{\mathbf{E}}}{\partial t} &amp;= \frac{4\pi}{c}\vec{\mathbf{j}} \\
\nabla \cdot \vec{\mathbf{E}} &amp;= 4 \pi \rho \\
\nabla \times \vec{\mathbf{E}}\, +\, \frac1c\, \frac{\partial\vec{\mathbf{B}}}{\partial t} &amp;= \vec{\mathbf{0}} \\
\nabla \cdot \vec{\mathbf{B}} &amp;= 0
\end{align}

&lt;h2 id=&#34;流程图展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#流程图展示&#34;&gt;#&lt;/a&gt; 📊 流程图展示&lt;/h2&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;graph TD&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    A[开始] --&amp;gt; B&amp;#123;是否安装 Hexo?&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    B --&amp;gt;|是| C[安装 Shoka 主题]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    B --&amp;gt;|否| D[安装 Hexo]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    D --&amp;gt; C&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    C --&amp;gt; E[配置主题]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    E --&amp;gt; F[编写文章]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F --&amp;gt; G[部署博客]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    G --&amp;gt; H[完成]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sequenceDiagram&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    participant 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    participant Hexo&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    participant Shoka&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    用户-&amp;gt;&amp;gt;Hexo: 创建新文章&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Hexo-&amp;gt;&amp;gt;Shoka: 应用主题样式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Shoka-&amp;gt;&amp;gt;用户: 渲染页面&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    用户-&amp;gt;&amp;gt;Shoka: 查看效果&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
